export declare const DELIVERY_NOTE_HTML =
  '<!DOCTYPE html>\n<html lang="en">\n<head>\n  <meta charset="UTF-8" />\n  <title>Delivery Note {{document.number}}</title>\n  <style>\n    /* Delivery note-specific overrides */\n    .delivery-details {\n      display: flex;\n      justify-content: space-between;\n      align-items: flex-start;\n      margin-bottom: 20px;\n    }\n    .delivery-details .left {\n      flex: 1;\n    }\n    .delivery-details .right {\n      flex: 0 0 auto;\n    }\n    .addresses {\n      display: flex;\n      gap: 30px;\n      margin-bottom: 20px;\n    }\n    .addresses .address-block {\n      flex: 1;\n    }\n    .delivery-items-table {\n      width: 100%;\n      border-collapse: collapse;\n      margin-bottom: 16px;\n    }\n    .delivery-items-table thead th {\n      background: #f0f0f0;\n      font-size: 10px;\n      font-weight: 700;\n      text-transform: uppercase;\n      color: #555;\n      padding: 8px 6px;\n      border-bottom: 2px solid #ccc;\n      text-align: left;\n    }\n    .delivery-items-table thead th.text-right {\n      text-align: right;\n    }\n    .delivery-items-table thead th.text-center {\n      text-align: center;\n    }\n    .delivery-items-table tbody td {\n      padding: 6px;\n      border-bottom: 1px solid #e5e5e5;\n      font-size: 11px;\n      vertical-align: top;\n    }\n    .delivery-items-table tbody td.text-right {\n      text-align: right;\n    }\n    .delivery-items-table tbody td.text-center {\n      text-align: center;\n    }\n    .delivery-items-table tbody tr:nth-child(even) {\n      background: #f9f9f9;\n    }\n    .special-instructions {\n      margin-bottom: 16px;\n      padding: 10px 12px;\n      background: #fafafa;\n      border-left: 3px solid #ddd;\n      font-size: 11px;\n      line-height: 1.5;\n    }\n    .special-instructions .section-title {\n      font-size: 10px;\n      font-weight: 700;\n      text-transform: uppercase;\n      color: #888;\n      margin-bottom: 4px;\n    }\n    .received-section {\n      margin-top: 30px;\n      padding: 16px;\n      border: 1px solid #ccc;\n      border-radius: 4px;\n      page-break-inside: avoid;\n    }\n    .received-section .section-title {\n      font-size: 10px;\n      font-weight: 700;\n      text-transform: uppercase;\n      color: #888;\n      margin-bottom: 12px;\n    }\n    .received-section .confirmation {\n      font-size: 11px;\n      color: #555;\n      margin-bottom: 16px;\n    }\n  </style>\n</head>\n<body>\n  <div class="page">\n\n    \n<div class="header">\n  <div class="header-left">\n    {{#if branding.showLogo}}\n    {{#if company.logoUrl}}\n    <div class="logo-section">\n      <img src="{{company.logoUrl}}" alt="{{company.name}} logo" />\n    </div>\n    {{/if}}\n    {{/if}}\n    <div class="company-name">{{company.name}}</div>\n    {{#if company.legalName}}\n    <div class="company-legal-name">{{company.legalName}}</div>\n    {{/if}}\n  </div>\n  <div class="header-right">\n    <div class="company-details">\n      <p style="white-space:pre-line">{{company.address}}</p>\n      {{#if company.phone}}<p>Tel: {{company.phone}}</p>{{/if}}\n      {{#if company.email}}<p>{{company.email}}</p>{{/if}}\n      {{#if company.website}}<p>{{company.website}}</p>{{/if}}\n      {{#if branding.showVatNumber}}\n      {{#if company.vatNumber}}<p class="vat-number">VAT: {{company.vatNumber}}</p>{{/if}}\n      {{/if}}\n      {{#if branding.showCompanyReg}}\n      {{#if company.companyNumber}}<p class="company-reg">Reg: {{company.companyNumber}}</p>{{/if}}\n      {{/if}}\n    </div>\n  </div>\n</div>\n\n    <div class="document-title">Delivery Note</div>\n\n    <div class="delivery-details">\n      <div class="left">\n        <div class="document-details">\n          <table>\n            <tr><th>Delivery Note No.</th><td>{{document.number}}</td></tr>\n            <tr><th>Date</th><td>{{formatDate document.date}}</td></tr>\n            {{#if document.reference}}\n            <tr><th>Order Reference</th><td>{{document.reference}}</td></tr>\n            {{/if}}\n          </table>\n        </div>\n      </div>\n    </div>\n\n    <div class="addresses">\n      <div class="address-block">\n        <div class="label">Customer</div>\n        <div class="name">{{counterparty.name}}</div>\n        <div class="address">{{counterparty.address}}</div>\n      </div>\n      <div class="address-block">\n        <div class="label">Deliver To</div>\n        <div class="name">{{#if metadata.deliveryName}}{{metadata.deliveryName}}{{else}}{{counterparty.name}}{{/if}}</div>\n        <div class="address">{{#if metadata.deliveryAddress}}{{metadata.deliveryAddress}}{{else}}{{counterparty.address}}{{/if}}</div>\n      </div>\n    </div>\n\n    <table class="delivery-items-table">\n      <thead>\n        <tr>\n          <th style="width:30px">#</th>\n          <th style="width:100px">Item Code</th>\n          <th>Description</th>\n          <th class="text-right" style="width:80px">Quantity</th>\n        </tr>\n      </thead>\n      <tbody>\n        {{#each lines}}\n        <tr class="line-item-row">\n          <td>{{this.lineNumber}}</td>\n          <td>{{this.itemCode}}</td>\n          <td>{{this.description}}</td>\n          <td class="text-right">{{formatNumber this.quantity 0}}</td>\n        </tr>\n        {{/each}}\n      </tbody>\n    </table>\n\n    {{#if document.notes}}\n    <div class="special-instructions">\n      <div class="section-title">Special Instructions</div>\n      {{document.notes}}\n    </div>\n    {{/if}}\n\n    <div class="received-section">\n      <div class="section-title">Goods Received Confirmation</div>\n      <div class="confirmation">\n        I confirm that the goods listed above have been received in good condition.\n      </div>\n      <div class="signature-area">\n        <div class="signature-line">\n          <div class="label">Received by:</div>\n          <div class="line"></div>\n        </div>\n        <div class="signature-line">\n          <div class="label">Print name:</div>\n          <div class="line"></div>\n        </div>\n        <div class="signature-line">\n          <div class="label">Date:</div>\n          <div class="line"></div>\n        </div>\n      </div>\n    </div>\n\n    \n<div class="page-footer">\n  {{company.name}} &mdash; Generated by Nexa ERP\n  <div class="page-numbers">Page <span class="pageNumber"></span> of <span class="totalPages"></span></div>\n</div>\n\n  </div>\n</body>\n</html>';
